const amqp = require('amqplib');
const { Pool } = require('pg');
const Joi = require('joi');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'events';
const DB_CONFIG = {
  host: process.env.DB_HOST || 'localhost',
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME || 'eventdb',
  user: process.env.DB_USER || 'dbuser',
  password: process.env.DB_PASSWORD || 'dbpassword',
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
};

const pool = new Pool(DB_CONFIG);

const ALLOWED_MESSAGE_TYPES = new Set([
  'user.created',
  'user.updated',
  'order.placed',
  'order.cancelled',
  'inventory.updated'
]);

const ALLOWED_ACTIONS = new Set([
  'insert',
  'update',
  'delete'
]);

const messageSchema = Joi.object({
  type: Joi.string().valid(...ALLOWED_MESSAGE_TYPES).required(),
  action: Joi.string().valid(...ALLOWED_ACTIONS).required(),
  payload: Joi.object().required(),
  timestamp: Joi.date().iso().required(),
  correlationId: Joi.string().uuid().optional()
});

const userCreatedSchema = Joi.object({
  userId: Joi.string().uuid().required(),
  email: Joi.string().email().max(255).required(),
  username: Joi.string().alphanum().min(3).max(50).required(),
  role: Joi.string().valid('user', 'admin', 'moderator').default('user')
});

const userUpdatedSchema = Joi.object({
  userId: Joi.string().uuid().required(),
  email: Joi.string().email().max(255).optional(),
  username: Joi.string().alphanum().min(3).max(50).optional(),
  role: Joi.string().valid('user', 'admin', 'moderator').optional()
});

const orderPlacedSchema = Joi.object({
  orderId: Joi.string().uuid().required(),
  userId: Joi.string().uuid().required(),
  totalAmount: Joi.number().positive().max(1000000).required(),
  items: Joi.array().items(Joi.object({
    productId: Joi.string().uuid().required(),
    quantity: Joi.number().integer().positive().max(1000).required(),
    price: Joi.number().positive().max(100000).required()
  })).min(1).max(100).required()
});

const orderCancelledSchema = Joi.object({
  orderId: Joi.string().uuid().required(),
  reason: Joi.string().max(500).optional()
});

const inventoryUpdatedSchema = Joi.object({
  productId: Joi.string().uuid().required(),
  quantity: Joi.number().integer().min(0).max(1000000).required(),
  warehouseId: Joi.string().uuid().required()
});

const payloadSchemas = {
  'user.created': userCreatedSchema,
  'user.updated': userUpdatedSchema,
  'order.placed': orderPlacedSchema,
  'order.cancelled': orderCancelledSchema,
  'inventory.updated': inventoryUpdatedSchema
};

function validateMessage(message) {
  const { error: messageError, value: validatedMessage } = messageSchema.validate(message);
  
  if (messageError) {
    throw new Error(`Invalid message structure: ${messageError.message}`);
  }

  const payloadSchema = payloadSchemas[validatedMessage.type];
  if (!payloadSchema) {
    throw new Error(`No payload schema defined for message type: ${validatedMessage.type}`);
  }

  const { error: payloadError, value: validatedPayload } = payloadSchema.validate(validatedMessage.payload);
  
  if (payloadError) {
    throw new Error(`Invalid payload for ${validatedMessage.type}: ${payloadError.message}`);
  }

  return {
    ...validatedMessage,
    payload: validatedPayload
  };
}

async function handleUserCreated(payload) {
  const query = {
    text: 'INSERT INTO users (id, email, username, role, created_at) VALUES ($1, $2, $3, $4, NOW()) ON CONFLICT (id) DO NOTHING',
    values: [payload.userId, payload.email, payload.username, payload.role]
  };
  
  await pool.query(query);
  console.log(`User created: ${payload.userId}`);
}

async function handleUserUpdated(payload) {
  const updates = [];
  const values = [];
  let paramIndex = 1;

  if (payload.email) {
    updates.push(`email = $${paramIndex++}`);
    values.push(payload.email);
  }
  if (payload.username) {
    updates.push(`username = $${paramIndex++}`);
    values.push(payload.username);
  }
  if (payload.role) {
    updates.push(`role = $${paramIndex++}`);
    values.push(payload.role);
  }

  if (updates.length === 0) {
    console.log(`No updates for user: ${payload.userId}`);
    return;
  }

  updates.push(`updated_at = NOW()`);
  values.push(payload.userId);

  const query = {
    text: `UPDATE users SET ${updates.join(', ')} WHERE id = $${paramIndex}`,
    values: values
  };

  const result = await pool.query(query);
  console.log(`User updated: ${payload.userId}, rows affected: ${result.rowCount}`);
}

async function handleOrderPlaced(payload) {
  const client = await pool.connect();
  
  try {
    await client.query('BEGIN');

    const orderQuery = {
      text: 'INSERT INTO orders (id, user_id, total_amount, status, created_at) VALUES ($1, $2, $3, $4, NOW())',
      values: [payload.orderId, payload.userId, payload.totalAmount, 'placed']
    };
    await client.query(orderQuery);

    for (const item of payload.items) {
      const itemQuery = {
        text: 'INSERT INTO order_items (order_id, product_id, quantity, price) VALUES ($1, $2, $3, $4)',
        values: [payload.orderId, item.productId, item.quantity, item.price]
      };
      await client.query(itemQuery);
    }

    await client.query('COMMIT');
    console.log(`Order placed: ${payload.orderId}`);
  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
}

async function handleOrderCancelled(payload) {
  const query = {
    text: 'UPDATE orders SET status = $1, cancellation_reason = $2, updated_at = NOW() WHERE id = $3',
    values: ['cancelled', payload.reason || null, payload.orderId]
  };

  const result = await pool.query(query);
  console.log(`Order cancelled: ${payload.orderId}, rows affected: ${result.rowCount}`);
}

async function handleInventoryUpdated(payload) {
  const query = {
    text: `INSERT INTO inventory (product_id, warehouse_id, quantity, updated_at) 
           VALUES ($1, $2, $3, NOW()) 
           ON CONFLICT (product_id, warehouse_id) 
           DO UPDATE SET quantity = $3, updated_at = NOW()`,
    values: [payload.productId, payload.warehouseId, payload.quantity]
  };

  await pool.query(query);
  console.log(`Inventory updated: ${payload.productId} at warehouse ${payload.warehouseId}`);
}

const messageHandlers = {
  'user.created': handleUserCreated,
  'user.updated': handleUserUpdated,
  'order.placed': handleOrderPlaced,
  'order.cancelled': handleOrderCancelled,
  'inventory.updated': handleInventoryUpdated
};

async function processMessage(message) {
  let parsedMessage;
  
  try {
    parsedMessage = JSON.parse(message.content.toString());
  } catch (error) {
    console.error('Failed to parse message JSON:', error.message);
    return false;
  }

  try {
    const validatedMessage = validateMessage(parsedMessage);
    
    const handler = messageHandlers[validatedMessage.type];
    if (!handler) {
      console.error(`No handler found for message type: ${validatedMessage.type}`);
      return false;
    }

    await handler(validatedMessage.payload);
    return true;
  } catch (error) {
    console.error(`Error processing message:`, error.message);
    return false;
  }
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqp.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    await channel.assertQueue(QUEUE_NAME, {
      durable: true
    });

    channel.prefetch(1);

    console.log(`Waiting for messages in queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (message) => {
      if (message !== null) {
        const success = await processMessage(message);
        
        if (success) {
          channel.ack(message);
        } else {
          channel.nack(message, false, false);
        }
      }
    });

    process.on('SIGINT', async () => {
      console.log('Shutting down gracefully...');
      await channel.close();
      await connection.close();
      await pool.end();
      process.exit(0);
    });

  } catch (error) {
    console.error('Failed to start consumer:', error);
    if (channel) await channel.close();
    if (connection) await connection.close();
    await pool.end();
    process.exit(1);
  }
}

startConsumer();